149: 	console.log(`  git hash: ${hash}`);
150: 
151: 	console.log(`  database: ${nconf.get('database')}`);
152: 
153: 	await db.init();
154: 	const info = await db.info(db.client);
155: 
156: 	switch (nconf.get('database')) {
157: 		case 'redis':
158: 			console.log(`        version: ${info.redis_version}`);
159: 			console.log(`        disk sync:  ${info.rdb_last_bgsave_status}`);
160: 			break;
161: 
162: 		case 'mongo':
163: 			console.log(`        version: ${info.version}`);
164: 			console.log(`        engine:  ${info.storageEngine}`);
165: 			break;
166: 		case 'postgres':
167: 			console.log(`        version: ${info.version}`);
168: 			console.log(`        uptime:  ${info.uptime}`);
169: 			break;
170: 	}
171: 
172: 	const analyticsData = await analytics.getHourlyStatsForSet('analytics:pageviews', Date.now(), 24);
173: 	const graph = new CliGraph({
174: 		height: 12,
175: 		width: 25,
176: 		center: {
177: 			x: 0,
178: 			y: 11,
179: 		},
180: 	});
181: 	const min = Math.min(...analyticsData);
182: 	const max = Math.max(...analyticsData);
183: 
184: 	analyticsData.forEach((point, idx) => {
185: 		graph.addPoint(idx + 1, Math.round(point / max * 10));
186: 	});
187: 
188: 	console.log('');
189: 	console.log(graph.toString());
190: 	console.log(`Pageviews, last 24h (min: ${min}  max: ${max})`);
191: 	process.exit();
192: }
